@Component
public class InventoryConsumer {

    @KafkaListener(topics = "order-created_v1", groupId = "inventory-group-v1")
    public void listenOrderCreatedV1(ConsumerRecord<String, GenericRecord> record) {
        try {
            // Deserialize and process the event
            OrderCreatedEvent_v1_0_0 event = new OrderCreatedEvent_v1_0_0(record.value());

            inventoryService.adjustInventory(event);
        } catch (Exception e) {
            logger.error("Failed to process order created v1 event: " + record.toString(), e);
        }
    }

    @KafkaListener(topics = "order-created_v2", groupId = "inventory-group-v2")
    public void listenOrderCreatedV2(ConsumerRecord<String, GenericRecord> record) {
        try {
