import org.apache.flink.streaming.connectors.jdbc.JdbcConnectionOptions;
import org.apache.flink.streaming.connectors.jdbc.JdbcSink;

public class FlinkJob {

    public static void main(String[] args) throws Exception {
        // Set up the execution environment
        final StreamExecutionEnvironment env = StreamExecutionEnvironment.getExecutionEnvironment();

        // Enable checkpointing with exactly-once mode and set interval
        env.enableCheckpointing(5000, CheckpointingMode.EXACTLY_ONCE);

        // Configure restart strategy
        env.getConfig().setRestartStrategy(RestartStrategies.fixedDelayRestart(
            3, // Number of restart attempts
            Time.seconds(10) // Delay between restarts in seconds
        ));

        // Kafka Consumer Configuration
        Properties kafkaProps = new Properties();
        kafkaProps.setProperty("bootstrap.servers", "localhost:9092");
        kafkaProps.setProperty("group.id", "flink-consumer-group");

        FlinkKafkaConsumer<String> kafkaConsumer = new FlinkKafkaConsumer<>(
            "order-created",
            new SimpleStringSchema(),
            kafkaProps
        );

        // Create a data stream from Kafka topic
        DataStream<String> orderEvents = env.addSource(kafkaConsumer);

        // Process the events (e.g., analytics, transformations)
        DataStream<Tuple2<Long, String>> processedOrders = orderEvents.map(new MapFunction<String, Tuple2<Long, String>>() {
            @Override
            public Tuple2<Long, String> map(String value) throws Exception {
                return new Tuple2<>(System.currentTimeMillis(), "Processed event: " + value);
            }
        });

        // Write the results to PostgreSQL
        JdbcConnectionOptions connectionOptions = JdbcConnectionOptions.builder()
            .withUrl("jdbc:postgresql://localhost:5432/orderdb")
            .withDriverName("org.postgresql.Driver")
            .withUsername("yourusername")
            .withPassword("yourpassword")
            .build();

        processedOrders.addSink(JdbcSink.sink(
            "INSERT INTO order_events (event_time, event_data) VALUES (?, ?)",
            (statement, tuple2) -> {
                statement.setTimestamp(1, new Timestamp(tuple2.f0));
                statement.setString(2, tuple2.f1);
            },
            connectionOptions
        ));

        // Execute the Flink job
        env.execute("Flink Order Processing Job");
    }
}
