        // Business logic to validate and process the order

        String topicName = "order-created";
        String key = order.getId().toString();
        OrderCreatedEvent event = new OrderCreatedEvent(order.getId(), LocalDateTime.now());

        Integer id = registerSchemaWithCompatibility(topicName, event);

        kafkaTemplate.send(topicName, key, event);
    }

    private Integer registerSchemaWithCompatibility(String subject, Object avroObject) {
        Schema schema = new Schema.Parser().parse(OrderCreatedEvent.SCHEMA$); // Replace with actual schema
        return schemaRegistryClient.register(subject, schema, CompatibilityLevel.BACKWARD_TRANSITIVE.toString());
    }
}
```

