### 4. Transactional Consumer Example

Ensure that consumers use transactions to process messages.

```java
import org.apache.kafka.clients.consumer.ConsumerRecord;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.kafka.annotation.KafkaListener;
import org.springframework.kafka.core.DefaultKafkaConsumerFactory;
import org.springframework.kafka.listener.ContainerProperties;
import org.springframework.stereotype.Component;

@Component
public class InventoryConsumer {

    @Autowired
    private InventoryService inventoryService;

    @Bean
    public ContainerProperties containerProperties() {
        ContainerProperties containerProps = new ContainerProperties("order-created");
        containerProps.setAckMode(ContainerProperties.AckMode.MANUAL_IMMEDIATE);
        return containerProps;
    }

    @KafkaListener(topics = "order-created", groupId = "inventory-group")
    public void listenOrderCreated(ConsumerRecord<String, OrderEvent> record) {
        try {
            // Process the order creation event and adjust inventory accordingly
            inventoryService.adjustInventory(record.value());

            // Commit transaction
            consumer.commitSync(Collections.singletonMap(new TopicPartition(record.topic(), record.partition()), new OffsetAndMetadata(record.offset() + 1)));
        } catch (Exception e) {
            logger.error("Failed to process order created event: " + record.toString(), e);
        }
    }

    @Bean
    public DefaultKafkaConsumerFactory<String, OrderEvent> consumerFactory() {
        Map<String, Object> props = new HashMap<>();
        props.put(ConsumerConfig.BOOTSTRAP_SERVERS_CONFIG, "localhost:9092");
        props.put(ConsumerConfig.GROUP_ID_CONFIG, "inventory-group");
        props.put(ConsumerConfig.KEY_DESERIALIZER_CLASS_CONFIG, StringDeserializer.class);
        props.put(ConsumerConfig.VALUE_DESERIALIZER_CLASS_CONFIG, JsonSerializer.class);

        return new DefaultKafkaConsumerFactory<>(props);
    }
}
```

