### 2. Modify Saga Coordinator

Update your Saga Coordinator to publish an audit event before executing each compensating action.

#### Example Saga Coordinator Implementation:

```java
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.kafka.core.KafkaTemplate;
import org.springframework.stereotype.Service;

@Service
public class OrderSagaCoordinator {

    @Autowired
    private KafkaTemplate<String, SagaAuditEvent> kafkaTemplate;

    @Autowired
    private OrderService orderService;

    @Autowired
    private InventoryService inventoryService;

    @Autowired
    private PaymentService paymentService;

    @Autowired
    private NotificationService notificationService;

    public void processOrder(Order order) {
        try {
            // Step 1: Create order in the Order Service
            String orderId = orderService.createOrder(order);

            // Step 2: Adjust inventory levels in the Inventory Service
            inventoryService.adjustInventory(orderId, order.getItems());

            // Step 3: Process payment in the Payment Service
            paymentService.processPayment(orderId, order.getTotalAmount());

            // Step 4: Send confirmation email in the Notification Service
            notificationService.sendConfirmationEmail(orderId);

        } catch (Exception e) {
            logger.error("Error processing order", e);

            String sagaId = UUID.randomUUID().toString(); // Generate a unique saga ID

            // Rollback operations if any step fails
            try {
                kafkaTemplate.send("saga-audit", new SagaAuditEvent(sagaId, "refund-payment", "STARTED", System.currentTimeMillis()));

                paymentService.refundPayment(order.getId());
                kafkaTemplate.send("saga-audit", new SagaAuditEvent(sagaId, "refund-payment", "SUCCESS", System.currentTimeMillis()));
            } catch (Exception ex) {
                logger.error("Failed to refund payment", ex);
                kafkaTemplate.send("saga-audit", new SagaAuditEvent(sagaId, "refund-payment", "FAILED", System.currentTimeMillis()));
            }

            try {
                kafkaTemplate.send("saga-audit", new SagaAuditEvent(sagaId, "revert-inventory-adjustment", "STARTED", System.currentTimeMillis()));

                inventoryService.revertInventoryAdjustment(order.getId());
                kafkaTemplate.send("saga-audit", new SagaAuditEvent(sagaId, "revert-inventory-adjustment", "SUCCESS", System.currentTimeMillis()));
            } catch (Exception ex) {
                logger.error("Failed to revert inventory adjustment", ex);
                kafkaTemplate.send("saga-audit", new SagaAuditEvent(sagaId, "revert-inventory-adjustment", "FAILED", System.currentTimeMillis()));
            }

            try {
                kafkaTemplate.send("saga-audit", new SagaAuditEvent(sagaId, "cancel-order", "STARTED", System.currentTimeMillis()));

                orderService.cancelOrder(order.getId());
                kafkaTemplate.send("saga-audit", new SagaAuditEvent(sagaId, "cancel-order", "SUCCESS", System.currentTimeMillis()));
            } catch (Exception ex) {
                logger.error("Failed to cancel order", ex);
                kafkaTemplate.send("saga-audit", new SagaAuditEvent(sagaId, "cancel-order", "FAILED", System.currentTimeMillis()));
            }
        }
    }
}
