```java
import io.confluent.kafka.schemaregistry.client.SchemaRegistryClient;
import org.apache.avro.Schema;

public class SchemaRegistrationUtil {

    private final SchemaRegistryClient schemaRegistryClient;

    public SchemaRegistrationUtil(SchemaRegistryClient schemaRegistryClient) {
        this.schemaRegistryClient = schemaRegistryClient;
    }

    public void registerSchema(String subject, Schema schema) throws Exception {
        Integer id = schemaRegistryClient.register(subject, schema);

        // Set compatibility mode
        Map<String, String> compatConfig = new HashMap<>();
        compatConfig.put("compatibility", "BACKWARD_TRANSITIVE");
        schemaRegistryClient.setCompatibilityLevel(subject, compatConfig);

        logger.info("Schema registered with ID: {}", id);
    }
}
```

